 1	import React, { FC, ReactNode } from 'react';
 2	import classNames from 'classnames';
 3	
 4	import NewBadge from '@kubevirt-utils/components/badges/NewBadge/NewBadge';
 5	import HelpTextIcon from '@kubevirt-utils/components/HelpTextIcon/HelpTextIcon';
 6	import { PopoverPosition, Split, SplitItem, Switch } from '@patternfly/react-core';
 7	
 8	import ExternalLink from '../ExternalLink/ExternalLink';
 9	
10	import './section-with-switch.scss';
11	
12	type SectionWithSwitchProps = {
13	  externalLink?: string;
14	  helpTextIconContent?: ReactNode;
15	  id?: string;
16	  inlineCheckbox?: boolean;
17	  isDisabled?: boolean;
18	  maxWidth?: string;
19	  newBadge?: boolean;
20	  switchIsOn: boolean;
21	  title?: ReactNode;
22	  turnOnSwitch: (checked: boolean) => void;
23	};
24	const SectionWithSwitch: FC<SectionWithSwitchProps> = ({
25	  children,
26	  externalLink,
27	  helpTextIconContent,
28	  id,
29	  inlineCheckbox,
30	  isDisabled,
31	  maxWidth,
32	  newBadge = false,
33	  switchIsOn,
34	  title,
35	  turnOnSwitch,
36	}) => {
37	  const Wrapper = inlineCheckbox ? 'div' : Split;
38	  return (
39	    <Wrapper className="section-with-switch" id={id} style={{ maxWidth }}>
40	      <div className="section-with-switch__text">
41	        {title}
42	        {externalLink && <ExternalLink href={externalLink} />}
43	        {helpTextIconContent && (
44	          <SplitItem isFilled>
45	            <HelpTextIcon
46	              bodyContent={helpTextIconContent}
47	              helpIconClassName="section-with-switch__help-text-popover"
48	              position={PopoverPosition.right}
49	            />
50	            {newBadge && <NewBadge />}
51	          </SplitItem>
52	        )}
53	      </div>
54	      <SplitItem className={classNames({ 'section-with-switch__inline': inlineCheckbox })}>
55	        {children}{' '}
56	        <Switch
57	          isChecked={switchIsOn}
58	          isDisabled={isDisabled}
59	          onChange={(_, checked: boolean) => turnOnSwitch(checked)}
60	        />
61	      </SplitItem>
62	    </Wrapper>
63	  );
64	};
65	
66	export default SectionWithSwitch;

